import{_ as t,o as i,c as n,ak as a}from"./chunks/framework.B_unCYUt.js";const _=JSON.parse('{"title":"Attention is All You Need","description":"","frontmatter":{},"headers":[],"relativePath":"publications/Attention is All You Need.md","filePath":"publications/Attention is All You Need.md","lastUpdated":1736993751000}'),l={name:"publications/Attention is All You Need.md"};function o(r,e,s,d,c,u){return i(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="attention-is-all-you-need" tabindex="-1">Attention is All You Need <a class="header-anchor" href="#attention-is-all-you-need" aria-label="Permalink to “Attention is All You Need”">​</a></h1><h2 id="links" tabindex="-1">Links <a class="header-anchor" href="#links" aria-label="Permalink to “Links”">​</a></h2><ul><li><a href="https://arxiv.org/abs/1706.03762" target="_blank" rel="noreferrer">arxiv: Attention is All You Need</a></li><li><a href="https://mp.weixin.qq.com/s/sU2uK2kQVJxzXeVNTmvfYg" target="_blank" rel="noreferrer">公众号文章: Attention Is All You Need (Transformer) 论文精读</a></li></ul><h2 id="核心内容" tabindex="-1">核心内容 <a class="header-anchor" href="#核心内容" aria-label="Permalink to “核心内容”">​</a></h2><ul><li>注意力机制(Attention Mechanism) <ul><li><strong>自注意力机制</strong>(Self-Attention Mechanism)</li></ul></li><li><strong>“注意力机制”</strong>（Attention Mechanism）可以取代传统的基于递归神经网络（RNN）或卷积神经网络（CNN）的结构，在自然语言处理和序列任务中表现出更高的效率和效果。具体来说, Transformer架构完全依赖注意力机制进行建模，而不需要RNN等传统结构，显著提高了并行化能力，提升了训练速度。</li><li>其实，“注意力”这个名字取得非常不易于理解。这个机制应该叫做“全局信息查询”。做一次“注意力”计算，其实就跟去数据库了做了一次查询一样。</li><li><strong>Transformer架构</strong></li><li>位置编码(Positional Encoding)</li><li>提升训练并行度</li></ul><p><img src="https://wwfyde.oss-cn-hangzhou.aliyuncs.com/images/202409132238646.png" alt="Refer to caption"></p>',6)])])}const m=t(l,[["render",o]]);export{_ as __pageData,m as default};
